import React, { useState, useRef, useEffect } from 'react';
import './VoiceRecorder.css';

function VoiceRecorder({ onTranscriptionComplete, disabled }) {
  const [isRecording, setIsRecording] = useState(false);
  const [isPaused, setIsPaused] = useState(false);
  const [recordingTime, setRecordingTime] = useState(0);
  const [audioBlob, setAudioBlob] = useState(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [error, setError] = useState('');

  const mediaRecorderRef = useRef(null);
  const audioChunksRef = useRef([]);
  const timerIntervalRef = useRef(null);
  const streamRef = useRef(null);

  // Cleanup on unmount
  useEffect(() => {
    return () => {
      stopRecording();
      if (streamRef.current) {
        streamRef.current.getTracks().forEach(track => track.stop());
      }
    };
  }, []);

  const startRecording = async () => {
    try {
      setError('');

      // Request microphone access
      const stream = await navigator.mediaDevices.getUserMedia({ 
        audio: {
          echoCancellation: true,
          noiseSuppression: true,
          sampleRate: 44100
        } 
      });

      streamRef.current = stream;

      // Create MediaRecorder
      const mediaRecorder = new MediaRecorder(stream, {
        mimeType: 'audio/webm;codecs=opus'
      });

      mediaRecorderRef.current = mediaRecorder;
      audioChunksRef.current = [];

      mediaRecorder.ondataavailable = (event) => {
        if (event.data.size > 0) {
          audioChunksRef.current.push(event.data);
        }
      };

      mediaRecorder.onstop = () => {
        const audioBlob = new Blob(audioChunksRef.current, { type: 'audio/webm' });
        setAudioBlob(audioBlob);

        // Stop all tracks
        if (streamRef.current) {
          streamRef.current.getTracks().forEach(track => track.stop());
        }
      };

      mediaRecorder.start();
      setIsRecording(true);
      setIsPaused(false);
      setRecordingTime(0);

      // Start timer
      timerIntervalRef.current = setInterval(() => {
        setRecordingTime(prev => prev + 1);
      }, 1000);

      console.log('🎤 Recording started');
    } catch (err) {
      console.error('Microphone access error:', err);
      setError('Could not access microphone. Please check permissions.');
    }
  };

  const pauseRecording = () => {
    if (mediaRecorderRef.current && mediaRecorderRef.current.state === 'recording') {
      mediaRecorderRef.current.pause();
      setIsPaused(true);
      clearInterval(timerIntervalRef.current);
      console.log('⏸️  Recording paused');
    }
  };

  const resumeRecording = () => {
    if (mediaRecorderRef.current && mediaRecorderRef.current.state === 'paused') {
      mediaRecorderRef.current.resume();
      setIsPaused(false);

      // Resume timer
      timerIntervalRef.current = setInterval(() => {
        setRecordingTime(prev => prev + 1);
      }, 1000);

      console.log('▶️  Recording resumed');
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && mediaRecorderRef.current.state !== 'inactive') {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
      setIsPaused(false);
      clearInterval(timerIntervalRef.current);
      console.log('⏹️  Recording stopped');
    }
  };

  const discardRecording = () => {
    setAudioBlob(null);
    setRecordingTime(0);
    audioChunksRef.current = [];
    console.log('🗑️  Recording discarded');
  };

  const submitRecording = async () => {
    if (!audioBlob) return;

    setIsProcessing(true);
    setError('');

    try {
      // Create FormData
      const formData = new FormData();
      formData.append('audio', audioBlob, 'recording.webm');

      // Get session ID from parent component (passed via props or context)
      const sessionId = localStorage.getItem('currentSessionId');
      const token = localStorage.getItem('token');

      console.log('📤 Uploading audio for transcription...');

      const response = await fetch(`http://localhost:5000/api/voice/${sessionId}/transcribe`, {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${token}`
        },
        body: formData
      });

      const data = await response.json();

      if (data.success) {
        console.log('✅ Transcription successful');
        console.log('   Text:', data.transcription.text);
        console.log('   Quality:', data.voiceAnalysis.quality.overall);

        // Call parent callback with transcription
        onTranscriptionComplete({
          text: data.transcription.text,
          voiceAnalysis: data.voiceAnalysis
        });

        // Reset
        discardRecording();
      } else {
        setError(data.message || 'Transcription failed');
      }
    } catch (err) {
      console.error('Transcription error:', err);
      setError('Failed to transcribe audio. Please try again.');
    } finally {
      setIsProcessing(false);
    }
  };

  const formatTime = (seconds) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  return (
    <div className="voice-recorder">
      {error && <div className="voice-error">{error}</div>}

      {!isRecording && !audioBlob && (
        <button 
          className="btn-voice btn-start-recording"
          onClick={startRecording}
          disabled={disabled || isProcessing}
        >
          <span className="voice-icon">🎤</span>
          <span>Start Voice Answer</span>
        </button>
      )}

      {isRecording && (
        <div className="recording-controls">
          <div className="recording-indicator">
            <span className="recording-dot"></span>
            <span className="recording-time">{formatTime(recordingTime)}</span>
          </div>

          <div className="recording-buttons">
            {!isPaused ? (
              <button className="btn-voice btn-pause" onClick={pauseRecording}>
                <span>⏸️ Pause</span>
              </button>
            ) : (
              <button className="btn-voice btn-resume" onClick={resumeRecording}>
                <span>▶️ Resume</span>
              </button>
            )}

            <button className="btn-voice btn-stop" onClick={stopRecording}>
              <span>⏹️ Stop</span>
            </button>
          </div>
        </div>
      )}

      {audioBlob && !isRecording && (
        <div className="recording-preview">
          <div className="preview-info">
            <span className="preview-icon">🎵</span>
            <span className="preview-duration">Recording: {formatTime(recordingTime)}</span>
          </div>

          <div className="preview-buttons">
            <button 
              className="btn-voice btn-discard" 
              onClick={discardRecording}
              disabled={isProcessing}
            >
              <span>🗑️ Discard</span>
            </button>

            <button 
              className="btn-voice btn-submit" 
              onClick={submitRecording}
              disabled={isProcessing}
            >
              <span>{isProcessing ? '⏳ Processing...' : '✓ Submit Answer'}</span>
            </button>
          </div>
        </div>
      )}
    </div>
  );
}

export default VoiceRecorder;
